mapper.select:
SELECT o.*, og.good_id, good.`name` AS good_name, og.count, og.standard, good.imgs, CASE WHEN oc.id IS NULL THEN 0 ELSE 1 END AS has_comment FROM t_order o JOIN order_goods og ON o.id = og.order_id JOIN good ON og.good_id = good.id LEFT JOIN order_comment oc ON oc.order_id = o.id WHERE o.user_id = #{userId}
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.state = #{state}
AND good.`name` LIKE CONCAT('%', #{goodName}, '%')
ORDER BY o.create_time DESC
